module top_module(
  A,
  B,
  CIN,
  SUM,
  COUT
);input A;
  input B;
  input CIN;
  output SUM;
  output COUT;

  wire sum_xor, w2, w3;

  // XOR gate to calculate SUM
  xor(sum_xor, A, B);
  xor(SUM, sum_xor, CIN);

  // AND gate to calculate COUT
  and(w2, A, B);
  and(w3, sum_xor, CIN);
  or(COUT, w2, w3);
endmodule
